export default function RedotsClubBingo(){
  const[called,setCalled]=useState([]);const[cur,setCur]=useState(null);const[rolling,setRolling]=useState(false);
  const[auto,setAuto]=useState(false);const[vOn,setVOn]=useState(true);const[vId,setVId]=useState("radialist");const[showVM,setShowVM]=useState(false);
  const timer=useRef(null);const histRef=useRef(null);const snd=useSound();const{announce,intro,stop:stopV}=useVoice();
  const ch=VOICE_CHARACTERS.find(v=>v.id===vId)||VOICE_CHARACTERS[0];
  const hot=useMemo(()=>called.length<4?null:analyzeCards(called),[called]);
  const callNum=useCallback(()=>{
    if(rolling)return;setRolling(true);let rc=0;
    const ri=setInterval(()=>{setCur(Math.floor(Math.random()*MAX_NUMBER)+1);snd.roll();rc++;
      if(rc>=10){clearInterval(ri);setCalled(prev=>{const av=[];for(let i=1;i<=MAX_NUMBER;i++)if(!prev.includes(i))av.push(i);if(!av.length){setRolling(false);return prev;}const num=av[Math.floor(Math.random()*av.length)];setCur(num);setRolling(false);snd.call();if(vOn){const c=VOICE_CHARACTERS.find(v=>v.id===vId)||VOICE_CHARACTERS[0];announce(num,c);}return[...prev,num];});}
    },70);
  },[rolling,snd,vOn,vId,announce]);
  useEffect(()=>{if(auto&&called.length<MAX_NUMBER){const c=VOICE_CHARACTERS.find(v=>v.id===vId)||VOICE_CHARACTERS[0];const ms=c.id==="scammer"||c.id==="grandpa"?5000:c.id==="radialist"?4500:4000;timer.current=setInterval(callNum,ms);}return()=>clearInterval(timer.current);},[auto,called.length,callNum,vId]);
  useEffect(()=>{if(called.length>=MAX_NUMBER)setAuto(false);},[called.length]);
  useEffect(()=>{if(histRef.current)histRef.current.scrollLeft=histRef.current.scrollWidth;},[called.length]);
  const reset=()=>{stopV();setCalled([]);setCur(null);setRolling(false);setAuto(false);snd.reset();};
  const pickV=(id)=>{setVId(id);if(vOn){const c=VOICE_CHARACTERS.find(v=>v.id===id);if(c)intro(c);}};
  const done=called.length>=MAX_NUMBER;

  return(
    <div style={{minHeight:"100vh",background:C.bg,display:"flex",flexDirection:"column",alignItems:"center",fontFamily:"var(--fB)",position:"relative"}}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@500;700;800&family=DM+Sans:wght@400;500;700&display=swap');
        :root{--fH:'Plus Jakarta Sans',sans-serif;--fB:'DM Sans',sans-serif}
        @keyframes ballPop{0%{transform:scale(.4) translateY(-20px);opacity:0}60%{transform:scale(1.1)}100%{transform:scale(1) translateY(0);opacity:1}}
        @keyframes pulse{0%,100%{transform:scale(1)}50%{transform:scale(1.06)}}
        @keyframes tumble0{0%,100%{transform:translateY(8px)}50%{transform:translateY(55px)}}
        @keyframes tumble1{0%,100%{transform:translateY(50px)}50%{transform:translateY(10px)}}
        @keyframes tumble2{0%,100%{transform:translateY(25px)}50%{transform:translateY(60px)}}
        @keyframes slideUp{0%{transform:translateY(100%)}100%{transform:translateY(0)}}
        *{box-sizing:border-box;margin:0;padding:0}body{background:${C.bg}}
        ::-webkit-scrollbar{height:4px}::-webkit-scrollbar-track{background:transparent}::-webkit-scrollbar-thumb{background:${C.greenBright}30;border-radius:10px}
      `}</style>

      {/* Pattern background */}
      <div style={{position:"fixed",inset:0,backgroundImage:`url(${PATTERN})`,backgroundSize:"300px",backgroundRepeat:"repeat",opacity:.3,pointerEvents:"none",zIndex:0}}/>

      <div style={{width:"100%",maxWidth:540,padding:"0 16px",position:"relative",zIndex:1}}>
        {/* Logo Bar - dark green */}
        <div style={{background:C.green,margin:"-0px -16px 0",padding:"18px 24px",display:"flex",alignItems:"center",justifyContent:"center",borderBottom:`3px solid ${C.gold}`}}>
          <img src={LOGO} alt="RedotsClub Brasil" style={{height:38}} />
        </div>
        {/* Title */}
        <div style={{textAlign:"center",padding:"14px 0 4px"}}>
          <h1 style={{fontSize:"clamp(1.8rem,5vw,2.4rem)",fontWeight:800,lineHeight:1.1,fontFamily:"var(--fH)",letterSpacing:-.5}}>
            <span style={{background:`linear-gradient(135deg,${C.greenBright},${C.gold})`,WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent"}}>BINGO</span>
          </h1>
        </div>

        {/* Machine - dark green */}
        <div style={{background:`linear-gradient(180deg,${C.greenLight},${C.green},${C.greenLight})`,borderRadius:22,border:`2px solid ${C.greenBright}40`,padding:"18px 16px",margin:"10px 0",position:"relative",overflow:"hidden",boxShadow:"0 4px 30px rgba(0,0,0,.15)"}}>
          <div style={{position:"absolute",inset:0,background:"repeating-linear-gradient(0deg,transparent,transparent 2px,rgba(0,0,0,.04) 2px,rgba(0,0,0,.04) 4px)",pointerEvents:"none",zIndex:2}}/>
          <div style={{position:"relative",height:160,display:"flex",alignItems:"center",justifyContent:"center",background:`radial-gradient(ellipse at center,${C.greenBright}15,transparent 70%)`,borderRadius:20,border:"1px solid rgba(255,255,255,.06)"}}>
            {rolling&&(<div style={{position:"absolute",inset:0,overflow:"hidden",borderRadius:20}}>{[...Array(8)].map((_,i)=>(<div key={i} style={{position:"absolute",width:11,height:11,borderRadius:"50%",background:i%3===0?C.greenBright:i%3===1?C.white:C.gold,opacity:.3,left:`${8+i*11}%`,animation:`tumble${i%3} ${.35+i*.08}s infinite ease-in-out`}}/>))}</div>)}
            <div style={{position:"relative",zIndex:3}}><BigBall number={cur} isRolling={rolling}/></div>
          </div>
          {called.length>0&&(<div style={{marginTop:12,position:"relative",zIndex:3}}>
            <div style={{fontSize:8,fontWeight:700,color:"rgba(255,255,255,.45)",letterSpacing:2,marginBottom:5,textAlign:"center"}}>LAST CALLED</div>
            <div ref={histRef} style={{display:"flex",gap:5,overflowX:"auto",padding:"2px 4px 6px",scrollBehavior:"smooth",justifyContent:called.length<=10?"center":"flex-start"}}>{called.map((n,i)=><SmallBall key={n} number={n} isLatest={i===called.length-1}/>)}</div>
          </div>)}
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:10,padding:"10px 16px",background:"rgba(0,0,0,.25)",borderRadius:12,border:"1px solid rgba(255,255,255,.06)",position:"relative",zIndex:3}}>
            <span style={{fontSize:10,color:"rgba(255,255,255,.5)",fontWeight:600,letterSpacing:1.5}}>BALLS DRAWN</span>
            <span style={{fontSize:22,fontWeight:800,fontFamily:"var(--fH)",color:called.length>=60?C.gold:called.length>=40?C.goldLight:C.white}}>{called.length}/{MAX_NUMBER}</span>
          </div>
        </div>

        <HotCardsPanel stats={hot}/>

        {/* Controls */}
        <div style={{display:"flex",gap:7,margin:"0 0 12px"}}>
          <button onClick={callNum} disabled={rolling||done} style={{flex:2,padding:"14px",fontSize:15,fontWeight:800,fontFamily:"var(--fH)",letterSpacing:3,border:"none",borderRadius:100,background:done?"#ddd":`linear-gradient(160deg,${C.gold},${C.goldLight},${C.gold})`,color:done?C.muted:C.green,cursor:done?"default":"pointer",opacity:rolling?.6:1,boxShadow:done?"none":`0 4px 20px ${C.gold}35`,transition:"all .2s"}}>{rolling?"ROLLING...":done?"ALL CALLED":"CALL! 🎱"}</button>
          <button onClick={()=>setAuto(!auto)} disabled={done} style={{padding:"14px 14px",fontSize:10,fontWeight:700,border:`2px solid ${auto?C.greenBright:C.green+"30"}`,borderRadius:100,background:auto?`${C.greenBright}15`:C.white,color:auto?C.greenBright:C.green,cursor:done?"default":"pointer"}}>{auto?"⏸":"▶"}</button>
          <button onClick={()=>setShowVM(true)} style={{padding:"14px 14px",border:`2px solid ${vOn?C.gold:C.muted}40`,borderRadius:100,background:vOn?`${C.gold}15`:C.white,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}><span style={{fontSize:16}}>{vOn?ch.emoji:"🔇"}</span></button>
          <button onClick={reset} style={{padding:"14px 14px",fontSize:12,fontWeight:700,border:`2px solid ${C.green}20`,borderRadius:100,background:C.white,color:C.muted,cursor:"pointer"}}>↺</button>
        </div>

        {/* Number Board - dark green */}
        <NumberBoard calledNumbers={called} latestNumber={cur&&!rolling?cur:null}/>

        <div style={{textAlign:"center",padding:"16px 0 24px"}}><img src={LOGO} alt="RedotsClub Brasil" style={{height:20,opacity:.3,marginBottom:6}}/><div style={{fontSize:8,color:C.muted+"80",letterSpacing:1}}>REDOTS CLUB BINGO</div></div>
      </div>

      <VoiceModal open={showVM} onClose={()=>setShowVM(false)} selected={vId} onSelect={pickV} voiceOn={vOn} onToggle={()=>setVOn(!vOn)}/>
    </div>);
}